import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { 
  BarChart3, 
  TrendingUp, 
  PieChart, 
  Calendar, 
  Filter,
  Download,
  Activity,
  CheckCircle,
  Clock,
  AlertCircle,
  FileText,
  ArrowUp,
  ArrowDown,
  MoreVertical,
  Printer,
  Mail,
  Share2,
  Users,
  Target,
  Zap,
  TrendingDown,
  Award,
  AlertTriangle,
  BarChart,
  LineChart,
  Eye,
  Timer,
  ThumbsUp,
  ThumbsDown,
  RefreshCw
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const Analytics = () => {
  const { api } = useAuth();
  const [stats, setStats] = useState({
    totalComplaints: 0,
    resolvedComplaints: 0,
    pendingComplaints: 0,
    inProgressComplaints: 0,
    byCategory: {},
    byPriority: {},
    monthlyTrends: [],
    avgResolutionTime: 0,
    satisfactionScore: 0,
    escalationRate: 0,
    repeatComplaintRate: 0,
    firstContactResolution: 0,
    backlogAge: 0,
    responseRate: 0,
    productivenessScore: 0
  });
  const [loading, setLoading] = useState(true);
  const [selectedPeriod, setSelectedPeriod] = useState('30');
  const [complaints, setComplaints] = useState([]);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    fetchAnalytics();
    fetchComplaintsForExport();
  }, []);

  const fetchAnalytics = async () => {
    try {
      setLoading(true);
      const response = await api.get('/complaints/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Error fetching analytics:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchComplaintsForExport = async () => {
    try {
      const response = await api.get('/complaints?size=1000&sortBy=createdAt&sortDir=desc');
      setComplaints(response.data.content || response.data || []);
    } catch (error) {
      console.error('Error fetching complaints for export:', error);
    }
  };

  const calculateAdvancedMetrics = (complaintsList) => {
    if (!complaintsList.length) return {};

    const resolved = complaintsList.filter(c => c.status === 'RESOLVED');
    const pending = complaintsList.filter(c => c.status === 'PENDING');
    const inProgress = complaintsList.filter(c => c.status === 'IN_PROGRESS');

    // Average Resolution Time (in hours)
    const resolutionTimes = resolved.map(c => {
      const created = new Date(c.createdAt);
      const resolved = new Date(c.resolvedAt || c.updatedAt);
      return (resolved - created) / (1000 * 60 * 60);
    });
    const avgResolutionTime = resolutionTimes.length ? 
      (resolutionTimes.reduce((a, b) => a + b, 0) / resolutionTimes.length).toFixed(1) : 0;

    // Satisfaction Score (simulated based on resolution time and priority)
    const satisfactionScore = Math.min(100, Math.max(0, 
      100 - (avgResolutionTime * 2) + (resolved.length / complaintsList.length * 50)
    )).toFixed(1);

    // Escalation Rate (high priority complaints older than 48 hours)
    const escalated = complaintsList.filter(c => 
      c.priority === 'HIGH' && 
      (Date.now() - new Date(c.createdAt)) > (48 * 60 * 60 * 1000) &&
      c.status !== 'RESOLVED'
    ).length;
    const escalationRate = ((escalated / complaintsList.length) * 100).toFixed(1);

    // Backlog Age (average age of unresolved complaints)
    const unresolved = complaintsList.filter(c => c.status !== 'RESOLVED');
    const backlogAge = unresolved.length ? 
      (unresolved.reduce((sum, c) => 
        sum + (Date.now() - new Date(c.createdAt)), 0
      ) / (unresolved.length * 1000 * 60 * 60)).toFixed(1) : 0;

    // First Contact Resolution (complaints resolved within 24 hours)
    const firstContactResolutions = resolved.filter(c => {
      const created = new Date(c.createdAt);
      const resolved = new Date(c.resolvedAt || c.updatedAt);
      return (resolved - created) < (24 * 60 * 60 * 1000);
    }).length;
    const firstContactResolution = resolved.length ? 
      ((firstContactResolutions / resolved.length) * 100).toFixed(1) : 0;

    // Productivity Score (complaints resolved per day)
    const daysPeriod = parseInt(selectedPeriod);
    const productivityScore = (resolved.length / daysPeriod).toFixed(1);

    return {
      avgResolutionTime,
      satisfactionScore,
      escalationRate,
      backlogAge,
      firstContactResolution,
      productivityScore
    };
  };

  const generatePDFReport = () => {
    setExporting(true);
    try {
      const doc = new jsPDF();
      const advancedMetrics = calculateAdvancedMetrics(complaints);

      // Header
      doc.setFontSize(20);
      doc.setTextColor(31, 41, 55);
      doc.text('Advanced Complaint Management Analytics Report', 20, 20);

      doc.setFontSize(12);
      doc.setTextColor(107, 114, 128);
      doc.text(`Generated on: ${new Date().toLocaleDateString()}`, 20, 30);
      doc.text(`Period: Last ${selectedPeriod} days`, 20, 37);
      doc.text(`Report ID: ${Date.now()}`, 20, 44);

      // Executive Summary
      doc.setFontSize(16);
      doc.setTextColor(31, 41, 55);
      doc.text('Executive Summary', 20, 60);

      doc.setFontSize(10);
      doc.setTextColor(107, 114, 128);
      doc.text('This comprehensive analytics report provides detailed insights into complaint management', 20, 68);
      doc.text('performance, resolution efficiency, and operational metrics.', 20, 74);

      // Key Performance Indicators
