              return (
                <div key={priority} className="bg-gradient-to-br p-4 rounded-xl text-white relative overflow-hidden">
                  <div className="absolute top-0 right-0 -mr-8 -mt-8 h-24 w-24 rounded-full bg-white/10 blur-xl"></div>
                  <div className="relative z-10">
                    <div className="flex items-center justify-between mb-3">
                      <span className="font-bold text-lg">{priority}</span>
                      <span className="text-2xl font-black">{count}</span>
                    </div>
                    <div className="space-y-1 text-sm">
                      <div className="flex justify-between">
                        <span className="opacity-90">Volume:</span>
                        <span className="font-semibold">{percentage}%</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="opacity-90">Resolved:</span>
                        <span className="font-semibold">{resolutionRate}%</span>
                      </div>
                      {priority === 'HIGH' && (
                        <div className="flex justify-between">
                          <span className="opacity-90">Escalated:</span>
                          <span className="font-semibold text-yellow-200">{escalatedCount}</span>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Status Overview with Advanced Metrics */}
      <div className="bg-white rounded-2xl shadow-lg p-6 border border-gray-100">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-gray-900 flex items-center">
            <FileText className="mr-3 h-6 w-6 text-green-600" />
            Comprehensive Status Overview
          </h2>
          <button className="text-sm font-medium text-green-600 hover:text-green-700">View All</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="text-center pig-6 bg-gradient-to-br from-green-50 to-green-100 rounded-xl border-2 border-green-200">
            <CheckCircle className="h-12 w-12 text-green-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-green-900">{stats.resolvedComplaints || 0}</div>
            <div className="text-sm font-medium text-green-700">Resolved</div>
            <div className="text-xs text-green-600 mt-1">{resolutionRate}% completion rate</div>
            <div className="text-xs text-green-500 mt-2">Avg: {advancedMetrics.avgResolutionTime}h</div>
          </div>

          <div className="text-center p-6 bg-gradient-to-br from-blue-50 to-blue-100 rounded-xl border-2 border-blue-200">
            <TrendingUp className="h-12 w-12 text-blue-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-blue-900">{stats.inProgressComplaints || 0}</div>
            <div className="text-sm font-medium text-blue-700">In Progress</div>
            <div className="text-xs text-blue-600 mt-1">Active work</div>
            <div className="text-xs text-blue-500 mt-2">Avg age: {advancedMetrics.backlogAge}h</div>
          </div>

          <div className="text-center p-6 bg-gradient-to-br from-amber-50 to-amber-100 rounded-xl border-2 border-amber-200">
            <Clock className="h-12 w-12 text-amber-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-amber-900">{stats.pendingComplaints || 0}</div>
            <div className="text-sm font-medium text-amber-700">Pending</div>
            <div className="text-xs text-amber-600 mt-1">Awaiting assignment</div>
            <div className="text-xs text-amber-500 mt-2">FCR: {advancedMetrics.firstContactResolution}%</div>
          </div>

          <div className="text-center p-6 bg-gradient-to-br from-purple-50 to-purple-100 rounded-xl border-2 border-purple-200">
            <Award className="h-12 w-12 text-purple-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-purple-900">{advancedMetrics.satisfactionScore}%</div>
            <div className="text-sm font-medium text-purple-700">Satisfaction</div>
            <div className="text-xs text-purple-600 mt-1">Customer rating</div>
            <div className="text-xs text-purple-500 mt-2">Productivity: {advancedMetrics.productivityScore}/d</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const AdvancedKpiCard = ({ title, value, icon, color, trend, description, target, status }) => {
  const isPositive = trend > 0;
  const statusColors = {
    'excellent': 'from-green-500 to-green-600',
    'good': 'from-blue-500 to-blue-600',
    'needs-improvement': 'from-amber-500 to-amber-600',
    'critical': 'from-red-500 to-red-600'
  };

  return (
    <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100 hover:shadow-xl transition-all duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className={`p-3 rounded-xl bg-gradient-to-r ${color} text-white`}>
          {icon}
        </div>
        <div className="flex flex-col items-end space-y-1">
          <div className={`flex items-center space-x-1 text-sm font-bold pxpig-1 rounded-full ${
            isPositive ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
          }`}>
            {isPositive ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />}
            <span>{Math.abs(trend)}%</span>
          </div>
          <div className={`text-xs pxpig-1 rounded-full bg-gradient-to-r ${statusColors[status]} text-white`}>
            {status.replace('-', ' ')}
          </div>
        </div>
      </div>

      <div>
        <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-1">{title}</h3>
        <div className="flex items-baseline space-x-2">
          <span className="text-3xl font-black text-gray-900">{value}</span>
        </div>
        <div className="flex items-center justify-between mt-2">
          <p className="text-xs text-gray-500">{description}</p>
          <span className="text-xs font-medium text-gray-400">Target: {target}</span>
        </div>
      </div>
    </div>
  );
};

const MetricItem = ({ label, value, target, status }) => {
  const statusColors = {
    'good': 'text-green-600 bg-green-50 border-green-200',
    'warning': 'text-yellow-600 bg-yellow-50 border-yellow-200',
    'critical': 'text-red-600 bg-red-50 border-red-200'
  };

  return (
    <div className={`flex items-center justify-between p-3 rounded-lg border ${statusColors[status]}`}>
      <div>
        <div className="text-sm font-medium">{label}</div>
        <div className="text-xs opacity-75">Target: {target}</div>
      </div>
      <div className="text-lg font-bold">{value}</div>
    </div>
  );
};

export default Analytics;
